public int blackjack(int a, int b) {
    if (a > 21 && b > 21) {
        return 0;
    }

    if (a <= 21 && b <= 21) {
        if (Math.abs(21 - a) < Math.abs(21 - b)) {
            return a;
        } else if (Math.abs(21 - a) > Math.abs(21 - b)) {
            return b;
        } else {
            return Math.min(a, b);
        }
    }

    if (a > 21 && b <= 21) {
        return b;
    }

    if (a <= 21 && b > 21) {
        return a;
    }

    return Math.max(a, b);
}

public int caughtSpeeding(int speed, boolean isBirthday) {
    int baseLimit = 60;
    int smallLimit = 80;
    int bigLimit = 81;

    if (isBirthday) {
        baseLimit += 5;
        smallLimit += 5;
    }

    if (speed <= baseLimit) {
        return 0;
    } else if (speed <= smallLimit) {
        return 1;
    } else {
        return 2;
    }
}

